function Card({ children, className = '' }: { children: ReactNode; className?: string }) {
  return <section className={`rounded-2xl border border-slate-200/75 bg-white/90 shadow-sm dark:border-white/10 dark:bg-white/[0.035] ${className}`}>{children}</section>;
}

function Badge({ children, tone = 'blue' }: { children: ReactNode; tone?: 'blue' | 'green' | 'amber' | 'slate' }) {
  const tones = { blue: 'bg-blue-500/10 text-blue-600 dark:text-cyan-300', green: 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-300', amber: 'bg-amber-500/10 text-amber-700 dark:text-amber-300', slate: 'bg-slate-500/10 text-slate-600 dark:text-slate-300' };
  return <span className={`inline-flex rounded-full px-2.5 py-1 text-[10px] font-bold ${tones[tone]}`}>{children}</span>;
}

function Heading({ eyebrow, title, copy, action }: { eyebrow: string; title: string; copy: string; action?: ReactNode }) {
  return <div className="mb-6 flex flex-col justify-between gap-4 sm:flex-row sm:items-end"><div><p className="text-[10px] font-bold uppercase tracking-[0.18em] text-blue-600 dark:text-cyan-400">{eyebrow}</p><h1 className="mt-2 font-heading text-2xl font-extrabold tracking-tight sm:text-3xl">{title}</h1><p className="mt-2 max-w-2xl text-xs leading-relaxed text-slate-500 dark:text-slate-400 sm:text-sm">{copy}</p></div>{action}</div>;
}

