function Matching({ community, setCommunity, connected, setConnected, selectedCommunity }: { community: string; setCommunity: (id: string) => void; connected: string[]; setConnected: (ids: string[]) => void; selectedCommunity: typeof communities[number] }) {
  return <><Heading eyebrow="Partner discovery" title="Matching" copy="Explore verified trading partners and Indonesian commodity communities aligned with your export goals." action={<Badge>{connected.length} connections</Badge>} />
    <div className="flex snap-x gap-4 overflow-x-auto pb-3">{matches.map((match) => <Card key={match.id} className="min-w-[280px] snap-start p-5 sm:min-w-[330px]"><div className="flex items-start justify-between"><span className="flex h-14 w-14 items-center justify-center rounded-2xl bg-gradient-to-br from-blue-600 to-cyan-400 font-heading text-lg font-black text-white">{match.initials}</span><b className="font-heading text-2xl text-blue-600 dark:text-cyan-300">{match.score}%</b></div><Badge tone="green">{match.trust}</Badge><h2 className="mt-4 font-heading text-lg font-extrabold">{match.name}</h2><p className="text-xs text-slate-400">{match.company} | {match.role}</p><p className="mt-3 flex items-center gap-1 text-[10px] font-bold text-slate-400"><MapPin className="h-3.5 w-3.5" />{match.place}</p><div className="mt-4 rounded-xl bg-slate-50 p-3 dark:bg-white/[0.04]"><b className="text-xs">{match.commodity}</b><p className="mt-1 text-[10px] leading-relaxed text-slate-400">{match.detail}</p></div><div className="mt-4 grid grid-cols-2 gap-2"><button className="min-h-10 rounded-xl border border-slate-200 text-xs font-bold dark:border-white/10">View profile</button><button onClick={() => setConnected(connected.includes(match.id) ? connected.filter((id) => id !== match.id) : [...connected, match.id])} className={`min-h-10 rounded-xl text-xs font-bold ${connected.includes(match.id) ? 'bg-emerald-500 text-white' : 'bg-blue-600 text-white'}`}>{connected.includes(match.id) ? 'Connected' : 'Connect'}</button></div></Card>)}</div>
    <div className="mt-6 grid gap-6 xl:grid-cols-[0.72fr_1.28fr]"><Card className="p-5 sm:p-6"><h2 className="font-heading text-lg font-extrabold">Search Indonesian commodity communities</h2><p className="mt-1 text-xs text-slate-400">Select a region to reveal its commodity network and active export partners.</p><div className="mt-5 space-y-2">{communities.map((item) => <button key={item.id} onClick={() => setCommunity(item.id)} className={`flex min-h-14 w-full items-center gap-3 rounded-xl border p-3 text-left transition ${community === item.id ? 'border-blue-500/40 bg-blue-500/[0.08] shadow-sm shadow-blue-500/10' : 'border-slate-200 hover:border-blue-500/20 dark:border-white/10'}`}><span className="flex h-9 w-9 items-center justify-center rounded-xl text-white" style={{ backgroundColor: item.color }}><MapPin className="h-4 w-4" /></span><span className="min-w-0 flex-1"><b className="block truncate text-xs">{item.name}</b><span className="text-[10px] text-slate-400">{item.region} | {item.commodity}</span></span><ChevronRight className="h-4 w-4 text-slate-300" /></button>)}</div></Card>
      <IndonesiaCommunityMap selected={community} setSelected={setCommunity} community={selectedCommunity} /></div></>;
}

function IndonesiaCommunityMap({ selected, setSelected, community }: { selected: string; setSelected: (id: string) => void; community: typeof communities[number] }) {
  const islandFill = (island: string) => community.island === island ? community.color : 'rgba(59,130,246,0.18)';
  const islandStroke = (island: string) => community.island === island ? community.color : 'rgba(34,211,238,0.28)';
  return <Card className="overflow-hidden">
    <div className="border-b border-slate-200/70 p-5 dark:border-white/10 sm:p-6"><div className="flex flex-col justify-between gap-3 sm:flex-row sm:items-start"><div><Badge>Indonesia community map</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">{community.region}</h2><p className="mt-1 text-xs text-slate-400">{community.name} is highlighted on the archipelago.</p></div><span className="flex h-11 w-11 items-center justify-center rounded-xl text-white shadow-lg" style={{ backgroundColor: community.color }}><MapPin className="h-5 w-5" /></span></div></div>
    <div className="relative bg-slate-950 p-3 sm:p-5"><div className="absolute inset-0 grid-pattern opacity-20" />
      <svg viewBox="0 0 820 330" className="relative z-10 h-auto w-full" role="img" aria-label="Stylized map of Indonesia with commodity community locations">
        <defs><filter id="islandGlow"><feGaussianBlur stdDeviation="5" result="blur" /><feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge></filter></defs>
        <path d="M65 62 C88 45 116 48 135 69 L205 174 C215 190 205 210 187 204 L153 178 L125 142 L96 113 L70 91 C60 82 57 70 65 62Z" fill={islandFill('sumatra')} stroke={islandStroke('sumatra')} strokeWidth="3" filter={community.island === 'sumatra' ? 'url(#islandGlow)' : undefined} />
        <path d="M208 228 C255 218 337 220 410 229 C421 231 424 242 413 247 C350 257 270 256 214 246 C202 244 198 233 208 228Z" fill={islandFill('java')} stroke={islandStroke('java')} strokeWidth="3" filter={community.island === 'java' ? 'url(#islandGlow)' : undefined} />
        <path d="M424 247 l18 5 l8 12 l-17 5 l-16 -9Z M457 257 l16 3 l9 10 l-13 7 l-18 -8Z M488 265 l17 3 l11 9 l-12 8 l-19 -8Z" fill={islandFill('nusa')} stroke={islandStroke('nusa')} strokeWidth="2" />
        <path d="M290 75 C327 56 389 58 421 87 L420 155 C408 181 374 202 330 190 L297 160 L278 115Z" fill={islandFill('kalimantan')} stroke={islandStroke('kalimantan')} strokeWidth="3" />
        <path d="M500 87 C518 72 542 80 547 100 L538 128 L562 116 L579 126 L558 143 L570 177 L553 196 L536 166 L515 183 L497 173 L515 143 L493 121Z" fill={islandFill('sulawesi')} stroke={islandStroke('sulawesi')} strokeWidth="3" filter={community.island === 'sulawesi' ? 'url(#islandGlow)' : undefined} />
        <path d="M614 130 l13 -8 l9 10 l-8 12 l-14 -4Z M640 154 l15 -8 l11 10 l-8 13 l-16 -2Z M617 181 l11 -8 l10 9 l-7 13 l-13 -2Z M668 188 l13 -5 l9 10 l-8 10 l-13 -3Z" fill={islandFill('maluku')} stroke={islandStroke('maluku')} strokeWidth="2.5" filter={community.island === 'maluku' ? 'url(#islandGlow)' : undefined} />
        <path d="M706 109 C741 96 789 107 806 132 L800 191 C775 208 738 205 710 188 L694 153Z" fill={islandFill('papua')} stroke={islandStroke('papua')} strokeWidth="3" filter={community.island === 'papua' ? 'url(#islandGlow)' : undefined} />
        <text x="100" y="212" fill="#64748b" fontSize="11">SUMATRA</text><text x="300" y="275" fill="#64748b" fontSize="11">JAVA</text><text x="315" y="125" fill="#64748b" fontSize="11">KALIMANTAN</text><text x="500" y="215" fill="#64748b" fontSize="11">SULAWESI</text><text x="615" y="220" fill="#64748b" fontSize="11">MALUKU</text><text x="742" y="225" fill="#64748b" fontSize="11">PAPUA</text>
        {communities.map((item) => <g key={item.id} onClick={() => setSelected(item.id)} className="cursor-pointer"><circle cx={item.markerX} cy={item.markerY} r={selected === item.id ? 15 : 10} fill={item.color} opacity={selected === item.id ? 0.25 : 0.12} /><circle cx={item.markerX} cy={item.markerY} r={selected === item.id ? 7 : 5} fill={item.color} stroke="#ffffff" strokeWidth="2" /><text x={item.markerX + 10} y={item.markerY - 10} fill={selected === item.id ? '#ffffff' : '#94a3b8'} fontSize="10" fontWeight="700">{item.id.toUpperCase()}</text></g>)}
      </svg>
    </div>
    <div className="grid gap-3 p-5 sm:grid-cols-3 sm:p-6"><div className="rounded-xl bg-slate-50 p-3 dark:bg-white/[0.04]"><p className="text-[9px] font-bold uppercase tracking-wider text-slate-400">Commodity</p><b className="mt-1 block text-xs">{community.commodity}</b></div><div className="rounded-xl bg-slate-50 p-3 dark:bg-white/[0.04]"><p className="text-[9px] font-bold uppercase tracking-wider text-slate-400">Members</p><b className="mt-1 block text-xs">{community.members} verified</b></div><div className="rounded-xl bg-slate-50 p-3 dark:bg-white/[0.04]"><p className="text-[9px] font-bold uppercase tracking-wider text-slate-400">Export partners</p><b className="mt-1 block text-xs">{community.partners} available</b></div><button className="flex min-h-11 items-center justify-center gap-2 rounded-xl bg-gradient-to-r from-blue-600 to-cyan-500 text-xs font-bold text-white sm:col-span-3">Explore community <ArrowRight className="h-4 w-4" /></button></div>
  </Card>;
}

function ExportPool({ selected, setSelected, selectedPool, navigate }: { selected: string; setSelected: (id: string) => void; selectedPool: typeof opportunities[number]; navigate: (section: Section) => void }) {
  return <><Heading eyebrow="Open buyer demand" title="Export Pool" copy="Browse current buyer needs, select an opportunity, and turn demand into an active export case." action={<Badge tone="green">{opportunities.length} open opportunities</Badge>} />
    <div className="grid gap-4 md:grid-cols-2 2xl:grid-cols-4">{opportunities.map((item) => <button key={item.id} onClick={() => setSelected(item.id)} className={`overflow-hidden rounded-2xl border bg-white p-5 text-left shadow-sm transition hover:-translate-y-1 dark:bg-white/[0.035] ${selected === item.id ? 'border-blue-500 ring-4 ring-blue-500/10' : 'border-slate-200/75 dark:border-white/10'}`}><div className="flex items-start justify-between"><span className="flex h-14 w-14 items-center justify-center rounded-2xl bg-gradient-to-br from-blue-600 to-cyan-400 font-heading font-black text-white">{item.initials}</span><Badge>{item.country}</Badge></div><p className="mt-5 text-[9px] font-bold uppercase tracking-wider text-slate-400">{item.category}</p><h2 className="mt-1 font-heading text-lg font-extrabold">{item.goods}</h2><p className="mt-2 text-xs text-slate-400">{item.buyer}</p><p className="mt-4 flex items-center gap-1 text-[10px] text-slate-400"><MapPin className="h-3.5 w-3.5" />Pickup: {item.pickup}</p><div className="mt-4 h-1.5 rounded-full bg-slate-100 dark:bg-white/10"><div className="h-full rounded-full bg-gradient-to-r from-blue-600 to-cyan-400" style={{ width: `${item.progress}%` }} /></div><div className="mt-3 flex justify-between text-[10px]"><span>{item.volume}</span><b>{item.value}</b></div></button>)}</div>
    <Card className="mt-6 p-5 sm:p-6"><div className="flex flex-col justify-between gap-5 sm:flex-row sm:items-center"><div><Badge tone="green">Selected opportunity</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">{selectedPool.goods} for {selectedPool.buyer}</h2><p className="mt-1 text-xs text-slate-400">{selectedPool.country} | {selectedPool.volume} | {selectedPool.value}</p></div><button onClick={() => navigate('export')} className="flex min-h-11 items-center justify-center gap-2 rounded-xl bg-gradient-to-r from-blue-600 to-cyan-500 px-5 text-xs font-bold text-white">Start Export Now <ArrowRight className="h-4 w-4" /></button></div></Card></>;
}

function ExportNow({ step, setStep, opportunity }: { step: number; setStep: (step: number) => void; opportunity: typeof opportunities[number] }) {
  const active = exportSteps[step];
  const guide = stageGuidance[step];
  const [completed, setCompleted] = useState<number[]>([]);
  const completeStage = () => setCompleted((items) => items.includes(step) ? items : [...items, step]);
  return <><Heading eyebrow="My guided export journey" title="Export Now" copy={`You are exporting 2 tons of coconut sugar to ${opportunity.buyer}. NEXIIport guides every party, action, and evidence checkpoint.`} action={<Badge tone="amber">{active}</Badge>} />
    <Card className="mb-5 p-4"><div className="flex gap-2 overflow-x-auto pb-1">{exportSteps.map((item, index) => <button key={item} onClick={() => setStep(index)} className={`min-h-11 shrink-0 rounded-xl px-3 text-[10px] font-bold transition ${index === step ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : completed.includes(index) || index < step ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-300' : 'bg-slate-100 text-slate-400 dark:bg-white/[0.04]'}`}>{completed.includes(index) && <Check className="mr-1 inline h-3 w-3" />}{item}</button>)}</div></Card>
    <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_360px]"><div className="min-w-0"><Card className="mb-4 p-5 sm:p-6"><Badge tone={completed.includes(step) ? 'green' : 'blue'}>{completed.includes(step) ? 'Stage action completed' : `Current stage: ${active}`}</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">{guide.title}</h2><div className="mt-5 space-y-4"><div><p className="text-[9px] font-bold uppercase tracking-wider text-blue-600 dark:text-cyan-300">What is happening</p><p className="mt-2 text-sm leading-relaxed text-slate-600 dark:text-slate-300">{guide.happening}</p></div><div className="border-t border-slate-200 pt-4 dark:border-white/10"><p className="text-[9px] font-bold uppercase tracking-wider text-amber-600 dark:text-amber-300">What I need to do</p><p className="mt-2 text-sm leading-relaxed text-slate-600 dark:text-slate-300">{guide.todo}</p></div></div></Card><ExportStage active={active} /><button onClick={completeStage} className={`mt-4 flex min-h-12 w-full items-center justify-center gap-2 rounded-xl text-xs font-bold ${completed.includes(step) ? 'bg-emerald-500 text-white' : 'bg-gradient-to-r from-blue-600 to-cyan-500 text-white shadow-lg shadow-blue-500/20'}`}>{completed.includes(step) ? <CheckCircle2 className="h-4 w-4" /> : <ArrowRight className="h-4 w-4" />}{completed.includes(step) ? 'Stage action completed' : guide.cta}</button></div><div className="space-y-4 xl:sticky xl:top-24 xl:self-start"><ExportAIPanel active={active} guide={guide} step={step} setStep={setStep} /><RevenueCard /><SupportCard /></div></div></>;
}

function ExportStage({ active }: { active: string }) {
  const [invited, setInvited] = useState(false);
  const [documents, setDocuments] = useState<Record<string, string>>({ 'Commercial Invoice': 'Attached', 'Packing List': 'Pending', 'Certificate of Origin': 'Pending', 'HS Code': 'Revised' });
  const [verified, setVerified] = useState(false);
  const [reviewResponded, setReviewResponded] = useState(false);
  const [readinessChecked, setReadinessChecked] = useState(false);
  const [proofs, setProofs] = useState<Record<string, string>>({ 'Packing proof': 'Uploaded', 'Dispatch proof': 'Missing', 'Inspection proof': 'Reviewed', 'Arrival proof': 'Missing' });
  const [shipmentPoint, setShipmentPoint] = useState(3);
  const [settlementChecked, setSettlementChecked] = useState(false);
  const action = 'flex min-h-10 items-center justify-center gap-2 rounded-xl px-3 text-[10px] font-bold transition';

  if (active === 'Dealing') {
    const participants = [['Me / Aruna Export', 'Joined', Send], ['Tokyo Natural Foods', 'Joined', Users], ['Logistics Partner', invited ? 'Joined' : 'Pending', Ship], ['Settlement Partner', 'Pending', Landmark], ['Verifier', 'Joined', ShieldCheck]] as const;
    return <Card className="p-5 sm:p-6"><Badge>Shared deal room</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Bring every export partner into one room.</h2><div className="mt-5 grid gap-3 sm:grid-cols-2">{participants.map(([label,status,Icon]) => <div key={label} className="flex items-center gap-3 rounded-xl border border-slate-200 p-3 dark:border-white/10"><span className="flex h-9 w-9 items-center justify-center rounded-xl bg-blue-500/10 text-blue-600 dark:text-cyan-300"><Icon className="h-4 w-4" /></span><div className="min-w-0 flex-1"><b className="block truncate text-xs">{label}</b><span className="text-[10px] text-slate-400">{status}</span></div><Badge tone={status === 'Joined' ? 'green' : 'amber'}>{status}</Badge></div>)}</div><button onClick={() => setInvited(true)} className={`${action} mt-5 w-full border border-blue-500/30 text-blue-600 dark:text-cyan-300`}><UserPlus className="h-4 w-4" />{invited ? 'Invitation sent' : 'Invite participant'}</button></Card>;
  }
  if (active === 'Document') {
    const update = (name: string, status: string) => setDocuments((current) => ({ ...current, [name]: status }));
    return <Card className="p-5 sm:p-6"><Badge>Exporter document exchange</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Attach and share documents with the buyer and verifier.</h2><p className="mt-2 text-xs text-slate-400">You control what leaves the exporter workspace and who receives it.</p><div className="mt-5 space-y-3">{Object.entries(documents).map(([name,status]) => <div key={name} className="flex min-h-14 flex-col gap-3 rounded-xl border border-slate-200 p-3 dark:border-white/10 sm:flex-row sm:items-center"><FileText className="h-4 w-4 shrink-0 text-blue-500" /><div className="min-w-0 flex-1"><b className="block text-xs">{name}</b><span className="text-[10px] text-slate-400">{status === 'Sent' ? 'Shared with buyer and verifier' : 'In exporter workspace'}</span></div><Badge tone={status === 'Pending' || status === 'Revised' ? 'amber' : 'green'}>{status}</Badge><div className="flex gap-2"><button onClick={() => update(name, 'Attached')} className={`${action} bg-slate-100 text-slate-600 dark:bg-white/[0.06] dark:text-slate-200`}><Paperclip className="h-3.5 w-3.5" />Attach</button><button onClick={() => update(name, 'Sent')} disabled={status === 'Pending'} className={`${action} bg-blue-600 text-white disabled:opacity-40`}><Send className="h-3.5 w-3.5" />Send</button></div></div>)}</div></Card>;
  }
  if (active === 'Verification') {
    const checks = [['Exporter profile verified', true], ['Buyer profile verified', true], ['Document consistency check', verified], ['Commodity suitability check', verified]] as const;
    return <Card className="p-5 sm:p-6"><Badge>Case validation</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Validate trust signals before partner review.</h2><div className="mt-5 space-y-3">{checks.map(([label,passed]) => <div key={label} className="flex min-h-14 items-center gap-3 rounded-xl bg-slate-50 p-3 dark:bg-white/[0.04]"><span className={`flex h-8 w-8 items-center justify-center rounded-full ${passed ? 'bg-emerald-500/15 text-emerald-500' : 'bg-amber-500/15 text-amber-500'}`}>{passed ? <Check className="h-4 w-4" /> : <Clock3 className="h-4 w-4" />}</span><b className="flex-1 text-xs">{label}</b><Badge tone={passed ? 'green' : 'amber'}>{passed ? 'Passed' : 'Pending'}</Badge></div>)}</div><button onClick={() => setVerified(true)} className={`${action} mt-5 w-full bg-gradient-to-r from-blue-600 to-cyan-500 text-white`}><ShieldCheck className="h-4 w-4" />{verified ? 'Case verified' : 'Run verification'}</button></Card>;
  }
  if (active === 'Review') {
    return <Card className="p-5 sm:p-6"><Badge tone="amber">Manual buyer review</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">The buyer is reading your verified export case.</h2><div className="mt-5 rounded-2xl border border-blue-500/20 bg-blue-500/[0.05] p-4"><div className="flex items-center gap-3"><span className="flex h-10 w-10 items-center justify-center rounded-xl bg-blue-600 text-xs font-black text-white">HK</span><div><b className="block text-xs">Hana Kobayashi</b><span className="text-[10px] text-slate-400">Tokyo Natural Foods - Buyer reviewer</span></div></div><p className="mt-4 text-xs leading-relaxed text-slate-600 dark:text-slate-300">&ldquo;Please confirm the final packing quantity before buyer submission.&rdquo;</p></div><div className="mt-4 space-y-2">{[['Packing List reviewed','Accepted'],['Commercial Invoice accepted','Accepted'],['Buyer confirmation',reviewResponded ? 'Response sent' : 'Waiting approval']].map(([label,status]) => <div key={label} className="flex items-center justify-between gap-3 rounded-xl bg-slate-50 p-3 dark:bg-white/[0.04]"><span className="text-xs">{label}</span><Badge tone={status === 'Waiting approval' ? 'amber' : 'green'}>{status}</Badge></div>)}</div><div className="mt-5 grid gap-2 sm:grid-cols-2"><button className={`${action} border border-slate-200 text-slate-600 dark:border-white/10 dark:text-slate-200`}><FileSearch className="h-4 w-4" />View review notes</button><button onClick={() => setReviewResponded(true)} className={`${action} bg-blue-600 text-white`}><MessageCircle className="h-4 w-4" />{reviewResponded ? 'Response sent' : 'Respond to buyer'}</button></div></Card>;
  }
  if (active === 'Escrow Readiness') {
    return <Card className="p-5 sm:p-6"><Badge tone="amber">Partner readiness signals</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Prepare the case for regulated partner review.</h2><div className="mt-5 rounded-2xl bg-slate-950 p-5 text-white"><div className="flex items-end justify-between"><div><p className="text-[9px] font-bold uppercase tracking-wider text-cyan-300">Readiness score</p><b className="mt-2 block font-heading text-4xl">{readinessChecked ? '91%' : '82%'}</b></div><ShieldCheck className="h-9 w-9 text-cyan-300" /></div><div className="mt-4 h-2 rounded-full bg-white/10"><div className="h-full rounded-full bg-gradient-to-r from-blue-500 to-cyan-300 transition-all" style={{ width: readinessChecked ? '91%' : '82%' }} /></div></div><div className="mt-4 grid gap-3 sm:grid-cols-2"><StatusTile title="Partner review" copy={readinessChecked ? 'Ready to share' : 'Pending readiness check'} icon={Landmark} /><StatusTile title="Funds readiness note" copy="Buyer signal confirmed" icon={Banknote} /></div><p className="mt-4 rounded-xl bg-amber-500/[0.08] p-4 text-[11px] leading-relaxed text-slate-300">NEXIIport provides readiness signals only. Financial action remains subject to regulated partner review.</p><button onClick={() => setReadinessChecked(true)} className={`${action} mt-5 w-full bg-blue-600 text-white`}><ShieldCheck className="h-4 w-4" />{readinessChecked ? 'Readiness checked' : 'Check readiness'}</button></Card>;
  }
  if (active === 'Proof') {
    const update = (name: string, status: string) => setProofs((current) => ({ ...current, [name]: status }));
    return <Card className="p-5 sm:p-6"><Badge>Trade evidence room</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Collect proof from real export checkpoints.</h2><p className="mt-2 text-xs text-slate-400">These files prove physical handling and delivery progress.</p><div className="mt-5 grid gap-3 sm:grid-cols-2">{Object.entries(proofs).map(([name,status]) => <div key={name} className="rounded-xl border border-slate-200 p-4 dark:border-white/10"><div className="flex items-start justify-between gap-2"><PackageCheck className="h-5 w-5 text-blue-500" /><Badge tone={status === 'Missing' ? 'amber' : 'green'}>{status}</Badge></div><b className="mt-4 block text-xs">{name}</b><div className="mt-4 flex gap-2"><button onClick={() => update(name, 'Uploaded')} className={`${action} flex-1 bg-slate-100 text-slate-600 dark:bg-white/[0.06] dark:text-slate-200`}><Upload className="h-3.5 w-3.5" />Attach</button><button onClick={() => update(name, 'Reviewed')} disabled={status === 'Missing'} className={`${action} flex-1 bg-blue-600 text-white disabled:opacity-40`}><Send className="h-3.5 w-3.5" />Send</button></div></div>)}</div></Card>;
  }
  if (active === 'Shipment') {
    const milestones = [['Warehouse', Warehouse], ['Picked up', PackageCheck], ['Origin port', Ship], ['In transit', Plane], ['Customs', ShieldCheck], ['Destination', MapPin], ['Delivered', CheckCircle2]] as const;
    return <Card className="p-5 sm:p-6"><Badge tone="green">Live shipment tracker</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Know where your goods are right now.</h2><div className="mt-5 overflow-hidden rounded-2xl bg-slate-950 p-4 text-white sm:p-5"><div className="flex items-center justify-between gap-3"><div><p className="text-[9px] font-bold uppercase tracking-wider text-cyan-300">Current position</p><b className="mt-1 block text-sm">{milestones[shipmentPoint][0]}</b></div><Plane className="h-6 w-6 text-cyan-300" /></div><div className="mt-6 flex gap-3 overflow-x-auto pb-2">{milestones.map(([label,Icon],index) => <button key={label} onClick={() => setShipmentPoint(index)} className="min-w-20 text-center"><span className={`mx-auto flex h-9 w-9 items-center justify-center rounded-full border-2 ${index <= shipmentPoint ? 'border-cyan-300 bg-cyan-300 text-slate-950' : 'border-white/20 bg-slate-900 text-slate-500'}`}><Icon className="h-4 w-4" /></span><span className="mt-2 block text-[8px] text-slate-400">{label}</span></button>)}</div><p className="mt-5 rounded-xl bg-white/[0.06] p-3 text-[10px] leading-relaxed text-slate-300">Goods are currently in transit from Tanjung Priok to Tokyo Port.</p></div><button onClick={() => setShipmentPoint((point) => Math.min(point + 1, milestones.length - 1))} className={`${action} mt-5 w-full bg-blue-600 text-white`}><MapPin className="h-4 w-4" />Track shipment</button></Card>;
  }
  if (active === 'Settlement') {
    return <Card className="p-5 sm:p-6"><Badge tone="green">Final partner process</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">Shipment complete. Final confirmation is in progress.</h2><div className="mt-5 grid gap-3 sm:grid-cols-3"><StatusTile title="Shipment milestones" copy="All completed" icon={CheckCircle2} /><StatusTile title="Buyer confirmation" copy={settlementChecked ? 'Confirmed' : 'Pending'} icon={Users} /><StatusTile title="Partner review" copy="In progress" icon={Landmark} /></div><div className="mt-5 rounded-2xl border border-blue-500/20 bg-blue-500/[0.05] p-5"><div className="flex gap-3"><Clock3 className="h-5 w-5 shrink-0 text-blue-500" /><div><b className="block text-xs">Settlement under partner review</b><p className="mt-2 text-[11px] leading-relaxed text-slate-500 dark:text-slate-300">The buyer and settlement partner are reviewing completed shipment evidence. Estimated completion: within 7 business days.</p></div></div></div><button onClick={() => setSettlementChecked(true)} className={`${action} mt-5 w-full bg-blue-600 text-white`}><FileSearch className="h-4 w-4" />{settlementChecked ? 'Settlement status checked' : 'Check settlement status'}</button></Card>;
  }
  if (active === 'Dealing') return <Card className="p-5 sm:p-6"><Badge>Participants in room</Badge><div className="mt-4 grid gap-3 sm:grid-cols-2">{[['Me — Aruna Export',Send],['Tokyo Natural Foods',Users],['Logistics Partner',Ship],['Settlement Partner',Landmark],['Verifier',ShieldCheck]].map(([label,Icon]) => <div key={label as string} className="flex items-center gap-3 rounded-xl border border-slate-200 p-3 text-xs font-bold dark:border-white/10"><span className="flex h-9 w-9 items-center justify-center rounded-xl bg-blue-500/10 text-blue-600 dark:text-cyan-300"><Icon className="h-4 w-4" /></span>{label as string}</div>)}</div></Card>;
  if (active === 'Document' || active === 'Verification' || active === 'Review') return <Card className="p-5 sm:p-6"><Badge>Document and verification room</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">I can see exactly what is ready and what needs action.</h2><div className="mt-5 space-y-3">{docs.map(([name,status]) => <button key={name} className="flex min-h-14 w-full items-center gap-3 rounded-xl border border-slate-200 p-3 text-left transition hover:border-blue-500/30 hover:bg-blue-500/[0.04] dark:border-white/10"><FileText className="h-4 w-4 text-blue-500" /><div className="flex-1"><b className="block text-xs">{name}</b><span className="text-[10px] text-slate-400">Shared with buyer and verifier</span></div><Badge tone={status.includes('Needs') ? 'amber' : 'green'}>{status}</Badge></button>)}</div><button className="mt-5 flex min-h-11 w-full items-center justify-center gap-2 rounded-xl border border-dashed border-blue-500/40 text-xs font-bold text-blue-600 dark:text-cyan-300"><Upload className="h-4 w-4" />Upload evidence</button></Card>;
  if (active === 'Escrow Readiness' || active === 'Proof') return <Card className="p-5 sm:p-6"><Badge tone="amber">Protection and evidence</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">I am preparing the case for regulated partner review.</h2><div className="mt-5 grid gap-3 sm:grid-cols-2">{[['Funds readiness','Confirmed by buyer signal',Banknote],['Payment protection layer','Partner review pending',ShieldCheck],['Inspection proof','Uploaded',FileCheck2],['Dispatch proof','Awaiting shipment',PackageCheck]].map(([title,copy,Icon]) => <button key={title as string} className="rounded-xl border border-slate-200 p-4 text-left transition hover:border-blue-500/30 dark:border-white/10"><Icon className="h-5 w-5 text-blue-500" /><b className="mt-3 block text-xs">{title as string}</b><span className="mt-1 block text-[10px] text-slate-400">{copy as string}</span></button>)}</div><div className="mt-5 rounded-xl bg-blue-500/[0.07] p-4"><div className="flex items-center justify-between"><div><p className="text-[9px] font-bold uppercase tracking-wider text-slate-400">Escrow readiness</p><b className="mt-1 block font-heading text-3xl text-blue-600 dark:text-cyan-300">82%</b></div><ShieldCheck className="h-8 w-8 text-blue-500" /></div></div><p className="mt-4 rounded-xl bg-amber-500/[0.08] p-4 text-[11px] leading-relaxed text-slate-500 dark:text-slate-300">NEXIIport visualizes readiness and evidence. Financial settlement remains subject to regulated partner review.</p></Card>;
  return <Card className="p-5 sm:p-6"><Badge tone="green">Shipment and settlement journey</Badge><h2 className="mt-3 font-heading text-xl font-extrabold">I can follow where my goods are and what comes next.</h2><div className="mt-6 overflow-hidden rounded-2xl bg-slate-950 p-4 text-white sm:p-5"><div className="flex items-center justify-between"><div><p className="text-[9px] font-bold uppercase tracking-wider text-cyan-300">Live shipment POV</p><b className="mt-1 block text-sm">Goods are currently in transit</b></div><Plane className="h-5 w-5 text-cyan-300" /></div><div className="relative mt-7"><div className="absolute left-4 right-4 top-4 h-0.5 bg-white/10" /><div className="absolute left-4 top-4 h-0.5 w-[42%] bg-gradient-to-r from-blue-500 to-cyan-300" /><div className="relative grid grid-cols-6 gap-1">{[['Warehouse',Warehouse],['Port',Ship],['In transit',Plane],['Customs',ShieldCheck],['Destination',MapPin],['Received',CheckCircle2]].map(([label,Icon],index) => <div key={label as string} className="min-w-0 text-center"><span className={`mx-auto flex h-8 w-8 items-center justify-center rounded-full border-2 ${index < 3 ? 'border-cyan-300 bg-cyan-400 text-slate-950' : 'border-white/20 bg-slate-900 text-slate-500'}`}><Icon className="h-3.5 w-3.5" /></span><span className="mt-2 hidden text-[8px] text-slate-400 sm:block">{label as string}</span></div>)}</div></div><p className="mt-6 rounded-xl bg-white/[0.06] p-3 text-[10px] text-slate-300">Kulon Progo → Tanjung Priok → Tokyo Port → Buyer warehouse</p></div><div className="mt-5 rounded-xl bg-emerald-500/[0.07] p-4"><div className="flex gap-3"><Clock3 className="h-4 w-4 text-emerald-500" /><div><b className="block text-xs">Settlement readiness: ready for partner review</b><p className="mt-1 text-[10px] text-slate-400">Verified documents, buyer confirmation, and shipment evidence support the recommendation.</p></div></div></div></Card>;
}

function ExportAIPanel({ active, guide, step, setStep }: { active: string; guide: typeof stageGuidance[number]; step: number; setStep: (step: number) => void }) {
  return <Card className="p-5"><div className="flex items-center gap-3"><span className="flex h-11 w-11 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-cyan-400 text-white shadow-lg shadow-blue-500/20"><Bot className="h-5 w-5" /></span><div><p className="text-[9px] font-bold uppercase tracking-wider text-blue-600 dark:text-cyan-300">NEXII AI guidance</p><b className="text-xs">{active} support</b></div></div><div className="mt-4 rounded-xl bg-blue-500/[0.07] p-4"><p className="text-[9px] font-bold uppercase tracking-wider text-blue-600 dark:text-cyan-300">AI suggestion</p><p className="mt-2 text-xs leading-relaxed">{guide.ai}</p></div><button onClick={() => setStep(Math.min(step + 1, exportSteps.length - 1))} disabled={step === exportSteps.length - 1} className="mt-4 flex min-h-11 w-full items-center justify-center gap-2 rounded-xl bg-slate-950 text-xs font-bold text-white disabled:opacity-40 dark:bg-cyan-300 dark:text-slate-950">Go to next stage <ArrowRight className="h-4 w-4" /></button><p className="mt-3 text-[9px] leading-relaxed text-slate-400">Prototype guidance only. Financial actions remain with regulated partners.</p></Card>;
}

function StatusTile({ title, copy, icon: Icon }: { title: string; copy: string; icon: IconType }) {
  return <div className="rounded-xl bg-slate-50 p-4 dark:bg-white/[0.04]"><Icon className="h-5 w-5 text-blue-500" /><b className="mt-3 block text-xs">{title}</b><span className="mt-1 block text-[10px] text-slate-400">{copy}</span></div>;
}

function RevenueCard() {
  return <Card className="p-5"><div className="flex items-start justify-between"><div><p className="text-[9px] font-bold uppercase tracking-wider text-emerald-600 dark:text-emerald-300">Estimated revenue</p><b className="mt-2 block font-heading text-2xl">USD 18,600</b></div><span className="flex h-10 w-10 items-center justify-center rounded-xl bg-emerald-500/10 text-emerald-500"><TrendingUp className="h-5 w-5" /></span></div><div className="mt-4 grid grid-cols-2 gap-3 text-[10px]"><div><span className="text-slate-400">Product</span><b className="mt-1 block">Coconut Sugar</b></div><div><span className="text-slate-400">Volume</span><b className="mt-1 block">2 tons</b></div><div><span className="text-slate-400">Destination</span><b className="mt-1 block">Japan</b></div><div><span className="text-slate-400">Estimated margin</span><b className="mt-1 block text-emerald-500">+18% projected</b></div></div><p className="mt-4 border-t border-slate-200 pt-3 text-[9px] leading-relaxed text-slate-400 dark:border-white/10">Based on current export case and expected settlement.</p></Card>;
}

function SupportCard() {
  const [contacted, setContacted] = useState(false);
  return <Card className="p-5"><div className="flex items-start gap-3"><span className="flex h-10 w-10 items-center justify-center rounded-xl bg-blue-500/10 text-blue-600 dark:text-cyan-300"><Headphones className="h-5 w-5" /></span><div><b className="block text-xs">Customer Support</b><p className="mt-1 text-[10px] leading-relaxed text-slate-400">Need help with export flow or documents?</p></div></div><button onClick={() => setContacted(true)} className="mt-4 flex min-h-10 w-full items-center justify-center gap-2 rounded-xl border border-blue-500/30 text-[10px] font-bold text-blue-600 dark:text-cyan-300"><MessageCircle className="h-3.5 w-3.5" />{contacted ? 'Support request sent' : 'Chat support'}</button><p className="mt-3 text-center text-[9px] text-slate-400">Response within 1 business day</p></Card>;
}
